"use client";

import { useRouter } from "next/navigation";
import { useState } from "react";
import { BookOpen, Target, Trophy, Mail, Phone, MapPin } from "lucide-react";

export default function Home() {
  const router = useRouter();
  const [active, setActive] = useState<string | null>(null);

  const handleTestClick = () => {
    const token = localStorage.getItem("token");

    if (!token) {
      router.push("/register");
    } else {
      router.push("/quiz");
    }
  };

  return (
    <div>

      {/* HOME */}
      <section id="home" className="h-screen flex flex-col items-center justify-center bg-gradient-to-r from-blue-500 to-purple-500 text-white text-center px-6">
        <h1 className="text-4xl font-bold mb-4">
          Crack Competitive Exams With Smart Practice
        </h1>

        <p className="mb-6 max-w-xl">
          Practice unlimited MCQs, track performance, and improve faster.
        </p>

        <button
          onClick={() => router.push("/register")}
          className="bg-white text-blue-600 px-6 py-2 rounded"
        >
          Start Free Now
        </button>
      </section>

      {/* TESTS */}
      <section id="tests" className="py-20 bg-gray-50 px-6">

        <h2 className="text-4xl font-bold text-center mb-12">
          Practice Tests
        </h2>

        <div className="max-w-4xl mx-auto space-y-4">

          {/* Topic */}
          <div className="border rounded-xl bg-white shadow">
            <div onClick={() => setActive(active === "topic" ? null : "topic")} className="flex justify-between p-5 cursor-pointer">
              <h3>📁 Topic Tests</h3>
              <span>{active === "topic" ? "-" : "+"}</span>
            </div>

            {active === "topic" && (
              <div className="p-4 space-y-2">
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">Quantitative Aptitude</div>
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">Reasoning Ability</div>
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">General Awareness</div>
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">English Language</div>
              </div>
            )}
          </div>

          {/* Sectional */}
          <div className="border rounded-xl bg-white shadow">
            <div onClick={() => setActive(active === "sectional" ? null : "sectional")} className="flex justify-between p-5 cursor-pointer">
              <h3>📂 Sectional Tests</h3>
              <span>{active === "sectional" ? "-" : "+"}</span>
            </div>

            {active === "sectional" && (
              <div className="p-4 space-y-2">
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">Maths Section Test</div>
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">Reasoning Section Test</div>
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">English Section Test</div>
              </div>
            )}
          </div>

          {/* Full */}
          <div className="border rounded-xl bg-white shadow">
            <div onClick={() => setActive(active === "full" ? null : "full")} className="flex justify-between p-5 cursor-pointer">
              <h3>🗂️ Full Length Tests</h3>
              <span>{active === "full" ? "-" : "+"}</span>
            </div>

            {active === "full" && (
              <div className="p-4 space-y-2">
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">Mock Test 1</div>
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">Mock Test 2</div>
                <div onClick={handleTestClick} className="border p-3 rounded cursor-pointer">Mock Test 3</div>
              </div>
            )}
          </div>

        </div>
      </section>

      {/* ABOUT (FULL UI SAME) */}
      <section id="about" className="bg-gray-50">

        <div className="bg-gradient-to-r from-blue-600 to-purple-600 text-white py-24 text-center">
          <h1 className="text-5xl font-bold mb-6">About StudyWeb</h1>
          <p className="max-w-2xl mx-auto text-lg">
            StudyWeb is a smart platform for competitive exam preparation.
          </p>
        </div>

        <div className="py-20 text-center">
          <h2 className="text-4xl font-bold mb-6">Our Mission</h2>
          <p className="text-gray-600 max-w-3xl mx-auto">
            Make learning smarter and easier for students.
          </p>
        </div>

        <div className="py-20 bg-white">
          <div className="grid md:grid-cols-3 gap-8 max-w-6xl mx-auto text-center">
            <Feature icon={<BookOpen />} title="Practice" />
            <Feature icon={<Target />} title="Analytics" />
            <Feature icon={<Trophy />} title="Ranking" />
          </div>
        </div>

      </section>

      {/* CONTACT (FULL UI SAME) */}
      <section id="contact" className="py-20 px-6 bg-gray-200">

        <div className="max-w-5xl mx-auto grid md:grid-cols-2 gap-10">

          <div>
            <p className="flex gap-2"><Mail /> support@studyweb.com</p>
            <p className="flex gap-2"><Phone /> +91 98765 43210</p>
            <p className="flex gap-2"><MapPin /> India</p>
          </div>

          <div className="bg-white p-6 rounded shadow">
            <input className="w-full mb-3 p-2 border rounded" placeholder="Name" />
            <input className="w-full mb-3 p-2 border rounded" placeholder="Email" />
            <textarea className="w-full mb-3 p-2 border rounded" placeholder="Message" />
            <button className="bg-blue-500 text-white px-4 py-2 rounded">
              Send
            </button>
          </div>

        </div>

      </section>

    </div>
  );
}

function Feature({ icon, title }: any) {
  return (
    <div className="p-6 bg-gray-100 rounded-xl">
      <div className="text-blue-600 mb-3 flex justify-center">{icon}</div>
      <h3 className="font-bold">{title}</h3>
    </div>
  );
}